 1	import { type ReactNode, useMemo, useState } from 'react';
 2	
 3	import ModalForm from '@components/ModalForm/ModalForm';
 4	import type { K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk';
 5	import { Form, Stack, StackItem } from '@patternfly/react-core';
 6	import { isEmpty } from '@utils/helpers';
 7	import { useForkliftTranslation } from '@utils/i18n';
 8	
 9	import { NODE_SELECTOR_MODAL_DESCRIPTION } from './utils/constants';
10	import { labelsArrayToObject } from './utils/labelsArrayToObject';
11	import { labelsObjectToArray } from './utils/labelsObjectToArray';
12	import type { LabelFields } from './utils/types';
13	import LabelsList from './LabelList';
14	import LabelRow from './LabelRow';
15	
16	type NodeSelectorModalProps = {
17	  onConfirm: (labels: Record<string, string | null>) => Promise<K8sResourceCommon>;
18	  title?: string;
19	  description?: ReactNode;
20	  initialLabels?: Record<string, string>;
21	};
22	
23	const NodeSelectorModal: React.FC<NodeSelectorModalProps> = ({
24	  description,
25	  initialLabels,
26	  onConfirm,
27	  title,
28	}) => {
29	  const { t } = useForkliftTranslation();
30	  const [labels, setLabels] = useState<LabelFields[]>(labelsObjectToArray(initialLabels));
31	  const isNotValid = useMemo(() => labels.some(({ key }) => isEmpty(key)), [labels]);
32	
33	  const onLabelChange = (changedLabel: LabelFields): void => {
34	    setLabels(
35	      labels.map((label) => {
36	        if (label.id === changedLabel.id) {
37	          return changedLabel;
38	        }
39	        return label;
40	      }),
41	    );
42	  };
43	
44	  const onLabelAdd = (newEntity: LabelFields): void => {
45	    const id = labels[labels.length - 1]?.id + 1 || 0;
46	    setLabels([...labels, { ...newEntity, id }]);
47	  };
48	
49	  const onLabelDelete = (idToDelete: number): void => {
50	    setLabels(labels.filter(({ id }) => id !== idToDelete));
51	  };
52	
53	  const onSelectorLabelAdd = () => {
54	    onLabelAdd({ id: -1, key: '', value: '' });
55	  };
56	
57	  return (
58	    <ModalForm
59	      testId="node-selector-modal"
60	      title={title ?? t('Edit node selectors')}
61	      onConfirm={async () => onConfirm(labelsArrayToObject(labels)) ?? {}}
62	      isDisabled={isNotValid}
63	    >
64	      <Form>
65	        <Stack hasGutter>
66	          <StackItem>{description ?? NODE_SELECTOR_MODAL_DESCRIPTION}</StackItem>
67	
68	          <LabelsList isEmpty={isEmpty(labels)} onLabelAdd={onSelectorLabelAdd}>
69	            {!isEmpty(labels) && (
70	              <>
71	                {labels.map((label, index) => (
72	                  <LabelRow
73	                    key={label.id}
74	                    label={label}
75	                    onChange={onLabelChange}
76	                    onDelete={onLabelDelete}
77	                    isLabelsVisible={index === 0}
78	                  />
79	                ))}
80	              </>
81	            )}
82	          </LabelsList>
83	        </Stack>
84	      </Form>
85	    </ModalForm>
86	  );
87	};
88	
89	export default NodeSelectorModal;

